class Solution {
    public int numberOfWays(int n, int x, int y) {
        final int MOD = (int)1e9 + 7;
        int[] dp = new int[x + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            int[] ndp = new int[x + 1];
            for (int j = 1; j <= x; j++) {
                for (int k = 1; k <= y; k++) {
                    ndp[j] = (ndp[j] + dp[j - 1]) % MOD;
                }
            }
            dp = ndp;
        }
        int res = 0;
        for (int i = 1; i <= x; i++) {
            res = (res + dp[i]) % MOD;
        }
        return res;
    }
}
